const HTMLConstructor={init(data){this.constructHTML(data);this.addToggleListeners();this.addTabListeners()},constructHTML(data){const createTabContent=(tabIndex,tabTitle,tabContent)=>{const createChildContent=(child,childIndex)=>{const[childTitle,childValues]=Object.entries(child)[0];return`
          <div class="tab-child">
            <details class="accordion-item" ${childIndex===0?"open":""}>
              <summary class="accordion-title">${childTitle}</summary>
              <div class="tab-child-content">${Array.isArray(childValues)?childValues.map(value=>`<div>${value}</div>`).join(""):""}</div>
            </details>
          </div>`};return`
        <div class="tab-content" data-tab="${tabTitle+tabIndex}" style="${tabIndex===0?"display: block;":"display: none;"}">
          ${Array.isArray(tabContent)?tabContent.map(createChildContent).join(""):""}
        </div>`};const createCategory=(categoryTitle,categoryContent,categoryIndex)=>{const createTab=(tab,tabIndex)=>{const[tabTitle]=Object.keys(tab);return`<div class="tab ${tabIndex===0&&categoryIndex===0?"active":""}" data-tab="${tabTitle+tabIndex}">
                  <div class="tab-title">${tabTitle}</div>
                </div>`};return`<div class="category ${categoryIndex===0?"active":""}">
                <div class="category-title">${categoryTitle}</div>
                <div class="category-content">
                  ${Array.isArray(categoryContent)?categoryContent.map(createTab).join(""):""}
                </div>
              </div>`};const categoryHTML=data.categories.map((category,index)=>{const[categoryTitle,categoryContent]=Object.entries(category)[0];return createCategory(categoryTitle,categoryContent,index)}).join("");const tabContentHTML=data.categories.map(category=>{const[categoryTitle,categoryContent]=Object.entries(category)[0];return`${Array.isArray(categoryContent)?categoryContent.map((tab,tabIndex)=>{const[tabTitle,tabContent]=Object.entries(tab)[0];return createTabContent(tabIndex,tabTitle,tabContent)}).join(""):""}`}).join("");document.getElementById("customizer").innerHTML=`
      <div class="cap-customizer">
        <div class="column">
          ${categoryHTML}
        </div>
        <div class="column">
          ${tabContentHTML}
        </div>
      </div>`},addToggleListeners(){const categoryDetails=document.querySelectorAll(".category-content details");categoryDetails.forEach(details=>{details.addEventListener("toggle",this.toggleOpenOneOnly.bind(this,details))})},toggleOpenOneOnly(currentDetails){const categoryDetails=currentDetails.parentNode.querySelectorAll("details");if(currentDetails.open){categoryDetails.forEach(details=>{if(details!==currentDetails&&details.open){details.open=false}})}},addTabListeners(){document.querySelectorAll(".tab").forEach(tab=>{tab.addEventListener("click",()=>{const tabIndex=tab.getAttribute("data-tab");const tabContents=document.querySelectorAll(".tab-content");document.querySelectorAll(".tab").forEach(tab=>{tab.classList.remove("active")});tabContents.forEach(content=>{content.style.display="none"});const selectedTabContent=document.querySelector(`.tab-content[data-tab="${tabIndex}"]`);if(selectedTabContent){selectedTabContent.style.display="block";tab.classList.add("active")}})})}};const data={modalId:"i8502",productHandle:"example-pants",categories:[{style:[{color:[{colors:["Red","Blue","Green","Yellow"]}]}]},{decoration:[{front:[{design:["left","center","right"]},{location:["center","right","left","none"]}]},{right:[{design:["left","center","right"]},{location:["right side panel","none"]}]},{left:[{design:["left","center","right"]},{location:["left side panel","across left side seam","none"]}]},{back:[{design:["left","center","right"]},{location:["across back seam","left back panel","none"]}]}]}]};HTMLConstructor.init(data);async function fetchData(){try{const response=await fetch("/products/example-pants?view=customizer-object");const data=await response.json();for(const property in data){if(data.hasOwnProperty(property)){console.log(property,data[property])}}}catch(error){console.log("Error:",error)}}fetchData();import*as THREE from"https://cdn.jsdelivr.net/npm/three@0.124/build/three.module.js";import{OrbitControls}from"https://cdn.jsdelivr.net/npm/three@0.124/examples/jsm/controls/OrbitControls.js";import{GLTFLoader}from"https://cdn.jsdelivr.net/npm/three@0.124/examples/jsm/loaders/GLTFLoader.js";import{RGBELoader}from"https://cdn.jsdelivr.net/npm/three@0.124/examples/jsm/loaders/RGBELoader.js";import{RoughnessMipmapper}from"https://cdn.jsdelivr.net/npm/three@0.124/examples/jsm/utils/RoughnessMipmapper.js";window.addEventListener("DOMContentLoaded",()=>{const scene=new THREE.Scene;const spotLight=new THREE.SpotLight(16777215);spotLight.intensity=1;spotLight.position.set(0,10,10);spotLight.angle=.3527087867259979;spotLight.penumbra=.1;scene.add(spotLight);const ambientLight=new THREE.AmbientLight(4210752);scene.add(ambientLight);const camera=new THREE.PerspectiveCamera(75,window.innerWidth/window.innerHeight,.1,1e3);camera.position.z=5;const renderer=new THREE.WebGLRenderer({antialias:true});renderer.setSize(window.innerWidth/2.5,window.innerHeight/1.5);renderer.setClearColor(16777215);document.getElementById("three-model-viewer").appendChild(renderer.domElement);const loader=new GLTFLoader;const controls=new OrbitControls(camera,renderer.domElement);let capModel;loader.load("https://blend-cole.myshopify.com/cdn/shop/t/20/assets/i8502.gltf",function(gltf){capModel=gltf.scene;const desiredScale=22;capModel.scale.set(desiredScale,desiredScale,desiredScale);scene.add(capModel);const raycaster=new THREE.Raycaster;const mouse=new THREE.Vector2;let intersected;const materialNames=[];capModel.traverse(node=>{if(node.isMesh&&node.material){const materialName=node.material.name;console.log("Material name:",materialName);if(!materialNames.includes(materialName)){materialNames.push(materialName)}}});const materialInputs=document.getElementsByClassName("material-input");Array.from(materialInputs).forEach(input=>{input.addEventListener("change",function(){changeColor(input.id)})});function changeColor(materialName){if(!capModel)return;const selectedColor=document.getElementById(materialName).value;console.log("Selected color:",selectedColor);capModel.traverse(node=>{if(node.isMesh&&node.material){const material=node.material;console.log("Node material name:",material.name);if(material.name===materialName){material.color.set(selectedColor)}}})}function onMouseMove(event){mouse.x=event.clientX/window.innerWidth*2-1;mouse.y=-(event.clientY/window.innerHeight)*2+1}window.addEventListener("mousemove",onMouseMove,false);function animate(){requestAnimationFrame(animate);controls.update();renderer.render(scene,camera)}animate()})});